const express = require('express');
const redis = require('redis');
const bodyParser = require('body-parser');
const { body, validationResult } = require('express-validator');

const app = express();
const client = redis.createClient();

app.use(bodyParser.json());

const ALLOWED_COMMANDS = ['GET', 'SET', 'DEL', 'EXISTS', 'KEYS'];

client.on('error', (err) => {
    console.error('Redis error:', err);
});

app.post('/search', 
    body('pattern').isString().trim().escape().custom((value) => {
        if (!/^[a-zA-Z0-9*]+$/.test(value)) {
            throw new Error('Invalid pattern');
        }
        return true;
    }),
    (req, res) => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            return res.status(400).json({ errors: errors.array() });
        }

        const pattern = req.body.pattern;
        client.keys(pattern, (err, keys) => {
            if (err) {
                return res.status(500).json({ error: 'Redis error' });
            }
            res.json({ keys });
        });
    }
);

app.post('/execute', 
    body('command').isString().trim().escape(),
    body('args').isArray().optional().customSanitizer((value) => value.map(arg => arg.toString())),
    (req, res) => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            return res.status(400).json({ errors: errors.array() });
        }

        const command = req.body.command.toUpperCase();
        if (!ALLOWED_COMMANDS.includes(command)) {
            return res.status(403).json({ error: 'Command not allowed' });
        }

        const args = req.body.args || [];
        client[command.toLowerCase()](...args, (err, result) => {
            if (err) {
                return res.status(500).json({ error: 'Redis error' });
            }
            res.json({ result });
        });
    }
);

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});